			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;text-align: center;&quot;&gt;वक्रता केंद्र पर&lt;/span&gt;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;text-align: center;&quot;&gt;वक्रता केंद्र पर&lt;/span&gt;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;समान&amp;nbsp;&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;text-align: center;&quot;&gt;वास्तविक, उल्टा&lt;/span&gt;&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center;&quot;&gt;फोकस पर&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center;&quot;&gt;अनंत पर&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बहुत बड़ा&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center;&quot;&gt;वास्तविक, उल्टा&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center;&quot;&gt;फोकस और वक्रता केंद्र के बीच&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center;&quot;&gt;अनंत और वक्रता केंद्र के बीच&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;बड़ा&amp;nbsp;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;text-align: center;&quot;&gt;वास्तविक, उल्टा&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;​&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/20/04/F1_Jayesh_Deepak_07.04.2020_D9.png&quot; style=&quot;width: 430px; height: 297px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Iodine&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Iodine&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;It was first discovered by Courtois in 1811 from the ashes of seaweeds.&lt;/li&gt;
		&lt;li&gt;Its atomic number is 53 and its mass number is 126.9.&lt;/li&gt;
		&lt;li&gt;It is found in compound form in seawater and seaweeds as iodides.&lt;/li&gt;
		&lt;li&gt;It is a non-metallic shining solid (possesses metallic lustre).&lt;/li&gt;
		&lt;li&gt;In the human body, it exists in the form of Thyroxin, an organic compound secreted by the&lt;strong&gt;&amp;nbsp;thyroid gland.&lt;/strong&gt;&lt;/li&gt;
		&lt;li&gt;Its deficiency in the Human body disturbs the working of the thyroid gland and leads to a goitre.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Fluorine&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;It was isolated by Moissan(1886).&lt;/li&gt;
		&lt;li&gt;It is a pale yellow gas.&lt;/li&gt;
		&lt;li&gt;Its atomic number is 9 and its mass number is 19.&lt;/li&gt;
		&lt;li&gt;It is the most reactive element among halogens.&lt;/li&gt;
		&lt;li&gt;It is the most electronegative element.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Chlorine&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;It is also called Oxymuriatic acid which&amp;nbsp;was discovered by Scheele (1774).&lt;/li&gt;
		&lt;li&gt;Its atomic number is 17 and its mass number is 35.45.&lt;/li&gt;
		&lt;li&gt;It reacts with lime to give bleaching powder (CaOCl&lt;sub&gt;2&lt;/sub&gt;).&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Bromine&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;It was first prepared by Ballard in 1826.&lt;/li&gt;
		&lt;li&gt;Its atomic number is 35 and its mass number is79.9.&lt;/li&gt;
		&lt;li&gt;It is used in the production of salts of bromine like bromide, bromate, hydrobromide, etc.&lt;/li&gt;
		&lt;li&gt;It is also used in the manufacturing of toxic and tear gases.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;&lt;span style=&quot;color: rgb(37, 37, 37);  &quot;&gt;सही उत्&amp;zwj;तर &lt;u&gt;&lt;strong&gt;आयोडीन&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;है।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u style=&quot;color: rgb(37, 37, 37);&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;आयोडीन&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;यह पहली बार 1811 में कौर्टोइस द्वारा समुद्री शैवाल की राख से खोजा गया था।&lt;/li&gt;
		&lt;li&gt;इसका परमाणु क्रमांक 53 और&amp;nbsp;द्रव्यमान संख्या 126.9 है।&lt;/li&gt;
		&lt;li&gt;यह समुद्री जल और समुद्री शैवाल में आयोडाइड के रूप में मिश्रित रूप में पाया जाता है।&lt;/li&gt;
		&lt;li&gt;यह एक अधात्विक शाइनिंग सॉलिड (धात्विक चमक वाला) है।&lt;/li&gt;
		&lt;li&gt;मानव शरीर में, यह थायरोक्सिन के रूप में मौजूद होता है, जो थायरॉयड ग्रंथि से स्रावित एक कार्बनिक यौगिक है।&lt;/li&gt;
		&lt;li&gt;मानव शरीर में इसकी कमी से थायरॉइड ग्रंथि की कार्यप्रणाली बाधित होती है और गण्डमाला हो जाती है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(37, 37, 37); &quot;&gt;फ्लुओरीन&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;इसे मोइसन (1886) द्वारा पृथक किया गया था।&lt;/li&gt;
		&lt;li&gt;यह एक हल्की पीली&amp;nbsp;गैस है।&lt;/li&gt;
		&lt;li&gt;इसका परमाणु क्रमांक 9 और&amp;nbsp;द्रव्यमान संख्या 19 है।&lt;/li&gt;
		&lt;li&gt;यह हैलोजनों में सबसे अधिक क्रियाशील तत्व है।&lt;/li&gt;
		&lt;li&gt;यह सबसे अधिक विद्युत ऋणात्मक तत्व है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(37, 37, 37);  &quot;&gt;क्लोरीन&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;इसे ऑक्सीमुरिएटिक एसिड भी कहा जाता है जिसकी खोज स्कील (1774) ने की थी।&lt;/li&gt;
		&lt;li&gt;इसका परमाणु क्रमांक 17 और&amp;nbsp;द्रव्यमान संख्या 35.45 है।&lt;/li&gt;
		&lt;li&gt;यह चूने के साथ अभिक्रिया करके विरंजक चूर्ण&amp;nbsp;(CaOCl&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;) देता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(37, 37, 37);  &quot;&gt;ब्रोमिन​&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;इसे पहली बार 1826 में बैलार्ड ने तैयार किया था।&lt;/li&gt;
		&lt;li&gt;इसका परमाणु क्रमांक 35 और द्रव्यमान संख्या 79.9 है।&lt;/li&gt;
		&lt;li&gt;इसका उपयोग ब्रोमीन के लवण जैसे ब्रोमाइड, ब्रोमेट, हाइड्रोब्रोमाइड आदि के उत्पादन में किया जाता है।&lt;/li&gt;
		&lt;li&gt;इसका उपयोग विषाक्त और &lt;span style=&quot;color: rgb(37, 37, 37); &quot;&gt;टीयर-गैस&lt;/span&gt; के निर्माण में भी किया जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Nucleus&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Chromosomes are &lt;strong&gt;thread-like structures&lt;/strong&gt; located &lt;strong&gt;inside the nucleus of animal and plant cells&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Each chromosome is &lt;strong&gt;made of protein and a single molecule of deoxyribonucleic acid (DNA)&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Passed from parents to offspring, DNA contains the specific instructions that make each type of living creature unique.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Types of Chromosomes&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;Chromosomes are divided into &lt;strong&gt;two parts (p and q arms)&lt;/strong&gt; with a constriction point called a centromere in the middle.&amp;nbsp;&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Metacentric &lt;/strong&gt;&amp;ndash; centromere is in &lt;strong&gt;middle&lt;/strong&gt;, meaning p and q arms are of comparable length (e.g. chromosomes 1, 3, 16, 19, 20).&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Submetacentric &lt;/strong&gt;&amp;ndash; centromere&lt;strong&gt; off-centre&lt;/strong&gt;, leading to shorter p arm relative to q arm (e.g. chromosomes 2, 4 &amp;ndash; 12, 17, 18, X).&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Acrocentric &lt;/strong&gt;&amp;ndash; centromere severely &lt;strong&gt;off-set from the centre&lt;/strong&gt;, leading to much shorter p arm (e.g. chromosomes 13 &amp;ndash; 15, 21, 22, Y).&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;Telocentric&lt;/strong&gt; &amp;ndash; centromere found at &lt;strong&gt;end of a chromosome&lt;/strong&gt;, meaning no p arm exists (chromosome not found in humans).&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;In humans, each cell normally contains &lt;strong&gt;23 pairs of chromosomes, for a total of 46&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Twenty-two of these pairs, called autosomes&lt;/strong&gt;, look the same in both males and females.&lt;/li&gt;
	&lt;li&gt;The &lt;strong&gt;23rd pair, the sex chromosomes&lt;/strong&gt;, differ between males and females.&lt;/li&gt;
	&lt;li&gt;Females have &lt;strong&gt;two copies of the X chromosome&lt;/strong&gt;, while males&lt;strong&gt; have one X and one Y chromosome&lt;/strong&gt;.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;b&gt;&lt;u&gt;केन्द्रक&amp;nbsp;&lt;/u&gt;&lt;/b&gt;है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;गुणसूत्र &lt;strong&gt;जंतु&amp;nbsp;और पादप&amp;nbsp;की कोशिकाओं के केंद्रक के अंदर स्थित धागे जैसी संरचनाएं हैं।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;प्रत्येक गुणसूत्र &lt;strong&gt;प्रोटीन और डीऑक्सीराइबोन्यूक्लिक अम्ल (&lt;/strong&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;DNA&lt;/span&gt;&lt;strong&gt;) के एकल अणु द्वारा बना होता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;माता-पिता से संतति में भेजे गए, डीएनए में विशिष्ट निर्देश होते हैं जो प्रत्येक प्रकार के जीवित प्राणी को अद्वितीय बनाते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;गुणसूत्रों के प्रकार&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;गुणसूत्र को एक संकुचन बिंदु, जिसे मध्य में एक गुणसूत्रबिंदु कहा जाता है, के साथ &lt;strong&gt;दो भागों (p और q भुजाओं)&lt;/strong&gt; में विभाजित किया जाता है।&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;मध्यकेंद्रीय&lt;/span&gt;&lt;strong&gt; &lt;/strong&gt;&amp;ndash; गुणसूत्रबिंदु &lt;strong&gt;मध्य&lt;/strong&gt; में होता है, जिसका अर्थ है कि p और q भुजाएँ तुलनात्मक लंबाई की होती हैं (जैसे गुणसूत्र 1, 3, 16, 19, 20)।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;उप-मध्यकेंद्रीय&amp;nbsp;&lt;/strong&gt;&amp;ndash; गुणसूत्रबिंदु &lt;strong&gt;केंद्र से परे&lt;/strong&gt; होता है, q भुजा के सापेक्ष p भुजा छोटी होती है (जैसे गुणसूत्र 2, 4 - 12, 17, 18, X)।&lt;/li&gt;
		&lt;li&gt;&lt;strong&gt;अग्रकेंद्रिक&lt;/strong&gt;&lt;strong&gt;&amp;nbsp;&lt;/strong&gt;&amp;ndash; गुणसूत्र&lt;strong&gt; केंद्र से बहुत दूर होता है&lt;/strong&gt;, जिससे p भुजा बहुत छोटी होती है (उदाहरण गुणसूत्र 13 - 15, 21, 22, Y)।&lt;/li&gt;
		&lt;li&gt;&lt;b&gt;अंतकेंद्री&lt;/b&gt;&amp;nbsp;&amp;ndash; गुणसूत्रकेंद्र,&lt;strong&gt; गुणसूत्र के अंत&lt;/strong&gt; में पाया जाता है, जिसका अर्थ है कि कोई p भुजा मौजूद नहीं होता है (गुणसूत्र मनुष्यों में नहीं पाया जाता है)।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;मनुष्यों में, प्रत्येक कोशिका में सामान्य रूप से &lt;strong&gt;23 युग्म और कुल 46 गुणसूत्र &lt;/strong&gt;होते हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;इन युग्मों में से बाइस, जिन्हें अलिंगगुणसूत्र कहा जाता है&lt;/strong&gt;, पुरुषों और महिलाओं दोनों में समान रुप से पाए जाते हैं।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;23वां युग्म, लिंग गुणसूत्र&lt;/strong&gt;, पुरुषों और महिलाओं के बीच भिन्न होते हैं।&lt;/li&gt;
	&lt;li&gt;महिलाओं में &lt;strong&gt;X गुणसूत्र की दो प्रतियां&lt;/strong&gt; होती हैं, जबकि पुरुषों में &lt;strong&gt;एक X और एक Y गुणसूत्र &lt;/strong&gt;होता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;&lt;u&gt;CONCEPT:&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;Heat Transfer:&lt;/strong&gt; Heat is transferred from one place to another in substance due to temperature difference.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:450px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td colspan=&quot;3&quot; style=&quot;width:601px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;Three modes of Transmission of heat&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:180px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;Conduction&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:208px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;Convection&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:167px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;Radiation&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:180px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;Heat dissipates from one place to another by &lt;strong&gt;molecular vibration&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:208px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;Heat is transfer from one place to another by &lt;strong&gt;transfer of molecules&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:167px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;It transfers heat in the form of &lt;strong&gt;electromagnetic wave&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:180px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;Conduction is relevant to &lt;strong&gt;solid only&lt;/strong&gt;.&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:208px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;Convection happens in &lt;strong&gt;liquid or gases&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:167px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;It can heat any form of material.&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:180px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;Need medium&lt;/strong&gt; to transfer heat&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:208px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;Need medium&lt;/strong&gt; to transfer heat&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:167px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;No need of medium&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:180px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;Good Conductor&lt;/strong&gt;- The objects which transfer heat easily. Ex- &lt;strong&gt;metals, human body&lt;/strong&gt; etc&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;Bad Conductor&lt;/strong&gt;- The objects which do not transfer heat easily. Ex- &lt;strong&gt;Wood, Air,&lt;/strong&gt; etc.&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;Thermal Insulator&lt;/strong&gt;- No heat is transferred by any means.&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;Ex- &lt;strong&gt;Abonite, asbestos&lt;/strong&gt; etc.&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:208px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;When molecules are heated they headed upward and upper molecules go downward and this cyclic process continues.&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&amp;nbsp;&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;Boiling of fluid&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:167px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;Heat travels in terms of energy packets or waves&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;The heat absorbed by body gain energy&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&amp;nbsp;&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;Radiations of Sun&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;Evaporation:&lt;/strong&gt; In this process the liquid form a substance tends to convert in the gaseous phase on the uppermost surface due to heat and pressure.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Condensation:&lt;/strong&gt; In this process the gaseous phase of an object tends to convert into liquid form due to pressure and temperature.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
&lt;strong&gt;&lt;u&gt;EXPLANATION:&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/20/05/F4_J.K_8.05.2020_Shashi_D1.png&quot; style=&quot;width: 512px; height: 256px;&quot; /&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;Once the lower molecules of pot get heated comes at the top.&lt;/li&gt;
	&lt;li&gt;And the upper molecules are heavy therefore goes down due to gravity.&lt;/li&gt;
	&lt;li&gt;This cyclic process continues heating occurs.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
While heating a &lt;strong&gt;fluid in pot Convection&lt;/strong&gt; takes place.&lt;/p&gt;<br><br>&lt;p&gt;&lt;strong&gt;&lt;u&gt;धारणा:&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;ऊष्मा &lt;span style=&quot;color: rgb(37, 37, 37); font-family: Roboto, arial, sans-serif;&quot;&gt;स्थानांतरण&lt;/span&gt;:&lt;/strong&gt; तापमान अंतर के कारण पदार्थ में एक स्थान से दूसरे स्थान पर ऊष्मा का&amp;nbsp;&lt;span style=&quot;color: rgb(37, 37, 37); font-family: Roboto, arial, sans-serif;&quot;&gt;स्थानांतरण&lt;/span&gt; होता है।&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:450px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td colspan=&quot;4&quot; style=&quot;width:601px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;ऊष्मा के&amp;nbsp;&lt;span style=&quot;color: rgb(37, 37, 37); font-family: Roboto, arial, sans-serif;&quot;&gt;स्थानांतरण&lt;/span&gt; के तीन तरीके&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:47px;&quot;&gt;
			&lt;p&gt;&lt;strong&gt;अनुक्र.&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:180px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(37, 37, 37); font-family: Roboto, arial, sans-serif;&quot;&gt;चालन&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:208px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(37, 37, 37); font-family: Roboto, arial, sans-serif;&quot;&gt;संवहन&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:167px;&quot;&gt;
			&lt;p align=&quot;center&quot; style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(37, 37, 37); font-family: Roboto, arial, sans-serif;&quot;&gt;विकिरण&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:47px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;1&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:180px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;आणविक कंपन&lt;/strong&gt; द्वारा ऊष्मा एक स्थान से दूसरे स्थान पर अपव्ययित होती है&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:208px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;अणुओं के स्थानांतरण&lt;/strong&gt; से ऊष्मा का एक स्थान से दूसरे स्थान पर स्थानांतरण होता है&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:167px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;यह &lt;strong&gt;विद्युत चुम्बकीय तरंग&lt;/strong&gt; के रूप में ऊष्मा को स्थानांतरित करता है&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:47px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;2&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:180px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;span style=&quot;color: rgb(37, 37, 37); font-family: Roboto, arial, sans-serif; text-align: -webkit-center;&quot;&gt;चालन&lt;/span&gt; &lt;strong&gt;केवल ठोस&lt;/strong&gt; के लिए प्रासंगिक है।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:208px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;संवहन तरल या गैसों में होता है&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:167px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;यह सामग्री के किसी भी रूप को गर्म कर सकता है।&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:47px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;3&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:180px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;ऊष्मा&amp;nbsp;स्थानांतरण के लिए &lt;strong&gt;माध्यम की आवश्यकता&lt;/strong&gt; है&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:208px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;ऊष्मा&amp;nbsp;स्थानांतरण के लिए &lt;strong&gt;माध्यम की आवश्यकता&lt;/strong&gt; है&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:167px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;माध्यम की जरूरत नहीं&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:47px;&quot;&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;4&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:180px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;अच्छा चालक&lt;/strong&gt;- वे वस्तुएं जो ऊष्मा को आसानी से स्थानांतरित करती हैं। उदा- &lt;strong&gt;धातु, मानव शरीर&lt;/strong&gt; आदि&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;खराब चालक&lt;/strong&gt;- वे वस्तुएं जो ऊष्मा को आसानी से स्थानांतरित&amp;nbsp;नहीं करते हैं। Ex- &lt;strong&gt;लकड़ी, वायु,&lt;/strong&gt; आदि।&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&lt;strong&gt;तापीय अवरोधक&lt;/strong&gt;- किसी भी माध्यम से कोई ऊष्मा स्थानांतरित&amp;nbsp;नहीं की जाती है।&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;Ex- &lt;strong&gt;एबोनाइट, एस्बेस्टस&lt;/strong&gt; आदि।&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:208px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;जब अणु गर्म होते हैं तो वे ऊपर की ओर बढ़ते हैं और ऊपरी अणु नीचे की ओर जाते हैं और यह चक्रीय प्रक्रिया जारी रहती है।&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&amp;nbsp;&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;द्रव का क्वथन&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:167px;&quot;&gt;
			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;ऊष्मा ऊर्जा पैकेट या तरंगों के संदर्भ में यात्रा करती है&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;निकाय द्वारा अवशोषित ऊष्मा ऊर्जा प्राप्त करती है&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;&amp;nbsp;&lt;/p&gt;

			&lt;p style=&quot;margin-left:4.15pt;&quot;&gt;सूर्य के विकिरण&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;&lt;strong&gt;वाष्पीकरण:&lt;/strong&gt; इस प्रक्रिया में तरल पदार्थ ऊष्मा और दबाव के कारण ऊपर की सतह पर गैसीय अवस्था में परिवर्तित हो जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;संघनन:&lt;/strong&gt; इस प्रक्रिया में किसी वस्तु का गैसीय चरण दबाव और तापमान के कारण तरल रूप में परिवर्तित हो जाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;br /&gt;
&lt;strong&gt;&lt;u&gt;&lt;span style=&quot;color: rgb(37, 37, 37); font-family: Roboto, arial, sans-serif;&quot;&gt;स्पष्टीकरण&lt;/span&gt;:&lt;/u&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&amp;nbsp;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/20/05/F4_J.K_8.05.2020_Shashi_D1.png&quot; style=&quot;width: 512px; height: 256px;&quot; /&gt;&lt;/p&gt;

&lt;ul style=&quot;list-style-type: disc;&quot;&gt;
	&lt;li&gt;
	&lt;p&gt;एक बार बर्तन के निचले अणु गर्म हो जाते हैं, ऊपर आते हैं।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li&gt;
	&lt;p&gt;और ऊपरी अणु भारी होते हैं इसलिए गुरुत्वाकर्षण के कारण नीचे चले जाते हैं।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li&gt;
	&lt;p&gt;यह चक्रीय प्रक्रिया तापन के समय जारी रहती है।&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;एक &lt;strong&gt;तरल पदार्थ को&lt;/strong&gt; &lt;strong&gt;बर्तन में&lt;/strong&gt; गर्म करते समय &lt;strong&gt;संवहन&lt;/strong&gt; होता है।&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Glycolysis is the process through which glucose is transformed into pyruvate or pyruvic acid. During this process ATP or Adenosine Triphosphate is also formed which is known as the &amp;ldquo;molecular unit of energy currency&amp;rdquo;.&lt;/li&gt;
	&lt;li&gt;Glycolysis can occur &lt;strong&gt;with or without oxygen&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;In the &lt;strong&gt;presence of oxygen,&lt;/strong&gt; glycolysis is the first stage of cellular respiration.&lt;/li&gt;
	&lt;li&gt;In the &lt;strong&gt;absence of oxygen&lt;/strong&gt;, glycolysis allows cells to make small amounts of ATP through the process of fermentation.&lt;/li&gt;
	&lt;li&gt;Glycolysis takes place in the cytosol of the cell&amp;#39;s cytoplasm.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;ul&gt;
	&lt;li&gt;ग्लाइकोलिसिस वह प्रक्रिया है जिसके माध्यम से ग्लूकोज को पाइरूवेट या पाइरुविक अम्ल&amp;nbsp;में परिवर्तित किया जाता है। इस प्रक्रिया के दौरान ATP या एडेनोसाइन ट्राईफॉस्फेट भी बनाया जाता है जिसे &amp;quot;मुद्रा की आणविक इकाई&amp;quot; के रूप में जाना जाता है।&lt;/li&gt;
	&lt;li&gt;ग्लाइकोलाइसिस ऑक्सीजन के साथ या उसके बिना हो सकता है।&lt;/li&gt;
	&lt;li&gt;ऑक्सीजन की उपस्थिति में, ग्लाइकोलाइसिस कोशिकीय श्वसन का पहला चरण है।&lt;/li&gt;
	&lt;li&gt;ऑक्सीजन की अनुपस्थिति में, ग्लाइकोलाइसिस कोशिकाओं को किण्वन की प्रक्रिया के माध्यम से एटीपी की छोटी मात्रा बनाने की अनुमति देता है।&lt;/li&gt;
	&lt;li&gt;ग्लाइकोलाइसिस कोशिका के कोशिका द्रव्य के साइटोसोल में होता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is the&amp;nbsp;&lt;u&gt;&lt;strong&gt;Pressure of air&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The velocity of sound in the air does not depend on the Pressure of air&lt;/strong&gt;.&lt;/li&gt;
	&lt;li&gt;Pressure- At a&amp;nbsp;constant temperature, the speed of sound does not depend on the pressure.&lt;/li&gt;
	&lt;li&gt;Thus an&lt;strong&gt; increase in the temperature &lt;/strong&gt;of the medium increases the speed of the sound.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Hence, the speed of sound depends on the humidity, although the change produced is very less&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Factors Affecting the Speed of Sound&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The density of the medium&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;For sound waves to travel, there is a requirement of the medium, and density of the medium is considered to be one of the factors on which the speed of sound depends.&lt;/li&gt;
		&lt;li&gt;When the medium is dense, the molecules in the medium are closely packed which means that the sound travels faster. Therefore, the speed of sound increases as the density of the medium increases.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The temperature and humidity of the medium&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;The temperature of the medium and the sound waves are directly proportional to each other. Therefore, as the temperature increases, the speed of sound increases.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;The speed of sound refers to the distance travelled per unit of time by a sound wave propagating through a medium.&lt;/li&gt;
	&lt;li&gt;The speed of sound in air is&lt;strong&gt; 343.2 m/s which translates to 1,236 km/h.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;वायु&amp;nbsp;के&amp;nbsp;दाब&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;वायु में ध्वनि का वेग वायु&amp;nbsp;के&amp;nbsp;दाब पर निर्भर नहीं करता है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;स्थिर तापमान पर दाब, ध्वनि का वेग दाब पर निर्भर नहीं करता है।&lt;/li&gt;
	&lt;li&gt;इस प्रकार माध्यम के &lt;strong&gt;तापमान में वृद्धि&lt;/strong&gt; से ध्वनि का वेग बढ़ जाता है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;इसलिए, ध्वनि का वेग&lt;/strong&gt;&lt;strong&gt; आर्द्रता पर निर्भर करता&lt;/strong&gt;&lt;strong&gt; है, हालांकि उत्पादित परिवर्तन बहुत कम है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;ध्वनि के वेग&lt;/strong&gt;&lt;strong&gt; को प्रभावित करने वाले कारक&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;माध्यम का घनत्व&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;यात्रा करने के लिए ध्वनि तरंगों के लिए माध्यम की आवश्यकता होती है और माध्यम के घनत्व को उन कारकों में से एक माना जाता है जिन पर ध्वनि का वेग निर्भर करता है।&lt;/li&gt;
		&lt;li&gt;जब माध्यम सघन होता है, तो माध्यम में कस कर संवेष्टित होते हैं&amp;nbsp; जिसका अर्थ है कि ध्वनि तेजी से यात्रा करती है। इसलिए, माध्यम का घनत्व बढ़ने पर ध्वनि का वेग बढ़ जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;माध्यम का तापमान और आर्द्रता&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;माध्यम और ध्वनि तरंगों का तापमान एक दूसरे के प्रत्यक्ष रूप से&amp;nbsp;आनुपातिक हैं। इसलिए, जैसे-जैसे तापमान बढ़ता है, ध्वनि का वेग बढ़ जाता है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;ध्वनि का वेग एक माध्यम से प्रचारित ध्वनि तरंग द्वारा समय की प्रति यूनिट में तय की गई दूरी को संदर्भित करता है।&lt;/li&gt;
	&lt;li&gt;वायु में ध्वनि का वेग &lt;strong&gt;343.2 मीटर/सेकंड है जो 1,236 किमी / घंटा में परिवर्तित होता है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct option is 4 i.e.,&amp;nbsp;&lt;u&gt;&lt;strong&gt;Parenchyma and collenchyma&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Cells of &lt;u&gt;&lt;strong&gt;parenchyma&lt;/strong&gt;&lt;/u&gt;&amp;nbsp;and &lt;u&gt;&lt;strong&gt;collenchyma&lt;/strong&gt;&lt;/u&gt; tissues are living cells.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Permanent tissues can be classified into two types:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;Simple permanent tissue&lt;/li&gt;
	&lt;li&gt;Complex Permanent tissue&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width: 300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;strong&gt;Simple permanent tissue&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;Parenchyma-&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;The cells of this tissue &lt;strong&gt;are living&lt;/strong&gt;&amp;nbsp;and have thin cell walls&lt;/li&gt;
				&lt;li&gt;It mainly acts as a packing tissue.&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;Collenchyma-&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;These cells are&lt;strong&gt; living cells&amp;nbsp;&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;Its main function is to provide flexibility to the plants&amp;nbsp;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;Sclerenchyma-&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;These cells&amp;nbsp;are &lt;strong&gt;dead cells.&lt;/strong&gt;&lt;/li&gt;
				&lt;li&gt;Its main function is to provide rigidity and mechanical support.&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;&lt;strong&gt;Complex Permanent tissue&lt;/strong&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;Xylem-&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;Xylem is responsible for the conduction of water and minerals from the roots to the leaves and stem.&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;Phloem-&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;Phloem helps in the translocation of food that is prepared by photosynthesis in the leaves to various parts of the plant&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;<br><br>&lt;p&gt;सही विकल्प 4 है, अर्थात &lt;u&gt;&lt;strong&gt;पैरेंकाइमा और कॉलेंकाइमा&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;पैरेंकाइमा और कॉलेंकाइमा&lt;/strong&gt;&lt;/u&gt; ऊतकों की कोशिकाएं जीवित कोशिकाएं होती हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;स्थायी ऊतकों को दो प्रकारों में वर्गीकृत किया जा सकता है:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;सरल स्थायी ऊतक&lt;/li&gt;
	&lt;li&gt;जटिल स्थायी ऊतक&lt;/li&gt;
&lt;/ul&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;background-color:  (255, 255, 255); width: 300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;strong&gt;सरल स्थायी ऊतक&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;span style=&quot;color:  (77, 81, 86); font-family: arial, sans-serif;&quot;&gt;पैरेंकाइमा&lt;/span&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;इस ऊतक की कोशिकाएँ &lt;strong&gt;जीवित &lt;/strong&gt;होती हैं और उनमें पतली कोशिका भित्ति होती है&lt;/li&gt;
				&lt;li&gt;यह मुख्य रूप से एक पैकिंग ऊतक के रूप में कार्य करता है।&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;span style=&quot;color:  (77, 81, 86); font-family: arial, sans-serif;&quot;&gt;कॉलेंकाइमा-&lt;/span&gt;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;ये कोशिकाएँ &lt;strong&gt;जीवित कोशिकाएँ&lt;/strong&gt; हैं&lt;/li&gt;
				&lt;li&gt;इसका मुख्य कार्य पौधों को लचीलापन प्रदान करना है&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;स्क्लेरेनकाइमा-&amp;nbsp;&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;ये कोशिकाएँ &lt;strong&gt;मृत कोशिकाएँ &lt;/strong&gt;हैं।&lt;/li&gt;
				&lt;li&gt;इसका मुख्य कार्य कठोरता और यांत्रिक सहायता प्रदान करना है।&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;background-color:  (255, 255, 255); width: 300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;जटिल स्थायी ऊतक&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;जाइलम-&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;जाइलम जड़ों से पत्तियों और तने तक जल और खनिजों के संचालन के लिए जिम्मेदार है।&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;फ्लोएम-&lt;/p&gt;

			&lt;ul&gt;
				&lt;li&gt;फ्लोएम भोजन के स्थानांतरण में सहायता करता है जो पत्तियों में प्रकाश संश्लेषण द्वारा पौधे के विभिन्न भागों में तैयार किया जाता है&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:300px&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;&lt;strong&gt;COMPOUND&lt;/strong&gt;&lt;/p&gt;
