			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;ALKANE&lt;/p&gt;
