			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;ALCOHOL&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;C&lt;sub&gt;n&lt;/sub&gt;H&lt;sub&gt;2n+1&lt;/sub&gt;OH&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
