	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;&lt;strong&gt;यौगिक&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;&lt;strong&gt;सामान्य सूत्र&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;अल्केन&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;C&lt;sub&gt;n&lt;/sub&gt;H&lt;sub&gt;&lt;sup&gt;2n&lt;/sup&gt;&lt;/sub&gt;+2&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;एल्कीन&amp;nbsp;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;C&lt;sub&gt;n&lt;/sub&gt;H&lt;sub&gt;2n&lt;/sub&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;एल्काइन&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:308px&quot;&gt;
			&lt;p style=&quot;text-align:center&quot;&gt;CnH&lt;sub&gt;2n&lt;/sub&gt;-2&lt;/p&gt;
